userDefinedLinkHintCss:
div > .vimiumHintMarker {
/* linkhint boxes */
background: #282a36;
padding: 1em;
border: 3px solid #bd93f9;
}

div.internalVimiumHintMarker span {
/* linkhint text */
color: #f8f8f2;
font-weight: bold;
font-size: 12px;
}

div > .vimiumHintMarker > .matchingCharacter {
color: #bd93f9;
}

#vomnibar {
    border: none;
    background: #282a36;
    width: 50vw;
    margin-left: 25%;
}

#vomnibar .vomnibarSearchArea {
    display: block;
    padding: 8px;
    border-top: 3px solid #bd93f9;
    border-radius: 4px;
    background-color: #282a36;
    border-bottom: none;
}

#vomnibar input {
    color: #f8f8f2;
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
    font-size: 20px;
    height: 2em;
    margin-bottom: 0;
    padding: 1.2em 1em;
    background-color: #44475a;
    border-radius: 4px;
    border: 1px solid transparent;
    box-shadow: #444 0px 0px 1px;
    width: 100%;
    outline: none;
    box-sizing: border-box;
}

#vomnibar ul {
    margin: 0;
    padding: 0;
    background-color: #282a36;
}

#vomnibar li {
    border-bottom: none;
    line-height: 1.1em;
    padding: 10px 0;
    font-size: 16px;
    /* color: black; */
    position: relative;
    display: list-item;
    margin: 8px;
    border-radius: 4px;
    transition: all .1s;
}

#vomnibar li .vomnibarSource {
    color: #ff79c6;
    margin-right: 4px;
}

#vomnibar li em, #vomnibar li .vomnibarTitle {
    color: #50fa7b;
    margin-left: 4px;
    font-weight: normal;
}

#vomnibar li em .vomnibarMatch, #vomnibar li .vomnibarTitle .vomnibarMatch {
    color: #bd93f9;
}

#vomnibar li .vomnibarMatch {
    font-weight: bold;
    color: #bd93f9;
}

#vomnibar li .vomnibarUrl {
    white-space: nowrap;
    color: #f1fa8c;
}

#vomnibar li.vomnibarSelected {
    background-color: #44475a;
    font-weight: normal;
    /*border-left: 6px solid #bd93f9;*/
}

#vomnibarInput::selection {
    background-color: #bd93f9;
}

div.vimiumHUD .vimiumHUDSearchArea{
    background-color: #282a36;
}

.vimiumHUDSearchArea{
    background-color: #282a36;
    border: 3px solid #bd93f9;
}

div.vimiumHUD .vimiumHUDSearchAreaInner {
    color: #f8f8f2;
}
